#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long M, N, K;
        scanf("%lld %lld %lld", &M, &N, &K);
        long long total = N * K;
        if (total < M) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

